Method.Implementation:
	// Save current device
	Set io=$io
	
	Try {
		// Always output to %FileCharacterStream
		If $get(export)="" {
			Set export=##class(%FileCharacterStream).%New()
			// JSON is always UTF-8
			Set export.TranslateTable="UTF8"
			Set filestream=1
		} Else {
			Set filestream = ($zobjclass(export)="%Library.FileCharacterStream")
		}
		If filestream {
			Set stream=export
		} Else {
			Set stream=##class(%FileCharacterStream).%New()
			Set stream.TranslateTable="UTF8"
		}
		
		// Force stream's file to open
		Set sc=stream.Write("")
		
		// Export JSON to the stream
		If $$$ISOK(sc) {
			Set file=stream.Filename ; get filename and make current device
			Use file:(/NOXY)
			Set sc=..%JSONExportInternal()
			// Don't Close file to leave stream positioned
			Use io
		}
		
		// Need to ensdure that LineTerminator is correct for the platform
		If $$$ISOK(sc) Set stream.LineTerminator=$select($$$isUNIX:$char(10),1:$char(13,10))

		// If we created the stream and caller passed in stream, then copy it to the caller's stream
		If 'filestream,$$$ISOK(sc) {	
			Set sc=export.CopyFrom(stream)
		}

	} Catch ex {
		Set sc=ex.AsStatus()
	}
   b
	Quit sc

	Try {
		Set sc=$$$OK
		
		// Do the export to current device now.
		Set %export=""
		Set sc=..%JSONExportToStringInternal()

	} Catch ex {
		If ex.Name="<MAXSTRING>" {
			Set sc=$$$ERROR($$$JSONMaxString,$$$mappingNameDisplay(%mappingName))
		} Else {
			Set sc=ex.AsStatus()
		}
	}

	Quit sc

// use the extent result set to find all person
Set extent = ##class(%ResultSet).%New("Sample.Person:Extent")
Do extent.Execute()

While (extent.Next()) {
	Set person = ..%OpenId(extent.GetData(1))
	Do person.PrintPerson()
}

Quit

// use dynamic SQL result set to find person data
Set query = ##class(%ResultSet).%New("%DynamicQuery:SQL")
Do query.Prepare("SELECT ID, Name, SSN FROM Sample.Person ORDER BY Name")
Do query.Execute()

While (query.Next()) {
	Write !,"Name: ", query.Get("Name"), ?30, query.Get("SSN")
}

Quit

// Set response to the concatenation of name.
Set response = name _ "||" _ name
QUIT 29

New %ROWCOUNT,%ROWID

&sql(UPDATE Sample.Person 
SET Home_City = :city, Home_State = :state 
WHERE Home_Zip = :zip)

// Return context information to client via %SQLProcContext object
If ($g(%sqlcontext)'=$$$NULLOREF) { 
	Set %sqlcontext.SQLCode = SQLCODE
	Set %sqlcontext.RowCount = %ROWCOUNT
}
QUIT 1
